// Extract and validate data from webhook
const body = $input.first().json.body || $input.first().json;
const { message, projectId, projectName, userId, userEmail, userName, teamMembers, projectData, humandChannelId } = body;

if (!message || !projectId) {
  return {
    error: true,
    errorMessage: 'Mensagem ou ID do projeto não fornecidos'
  };
}

// Format team members for context
const formattedTeamMembers = (teamMembers || []).map(m => ({
  id: m.id,
  name: m.name || m.full_name,
  email: m.email || '',
  role: m.role,
  humandChannelId: m.humandChannelId || null
}));

const teamMembersContext = formattedTeamMembers.length > 0
  ? formattedTeamMembers.map(m => `- ${m.name}${m.email ? ` (${m.email})` : ''} - ${m.role} [ID: ${m.id}]${m.humandChannelId ? ` [HumandID: ${m.humandChannelId}]` : ''}`).join('\n')
  : 'Nenhum membro de equipe associado a este projeto.';

// Format project stats
const stats = projectData?.stats || {};
const projectStatsContext = `
Estatísticas do Projeto:
- Total de tarefas: ${stats.total || 0}
- A fazer (todo): ${stats.todo || 0}
- Em progresso: ${stats.inProgress || 0}
- Em revisão: ${stats.review || 0}
- Concluídas: ${stats.done || 0}
- Bloqueadas: ${stats.blocked || 0}
- Pontos totais: ${stats.totalPoints || 0}
- Pontos concluídos: ${stats.completedPoints || 0}
- Percentual de conclusão: ${stats.completionPercentage || 0}%
`;

// Format workload
const workload = stats.workload || {};
const workloadContext = Object.keys(workload).length > 0
  ? Object.entries(workload)
      .sort((a, b) => b[1].points - a[1].points)
      .map(([name, data]) => `- ${name}: ${data.tasks} tarefas (${data.points} pontos)`)
      .join('\n')
  : 'Nenhuma tarefa atribuída no momento.';

// Format sprints
const sprints = projectData?.sprints || [];
const activeSprint = sprints.find(s => s.status === 'active') || null;
const sprintsContext = sprints.length > 0
  ? sprints.map(s => {
      const label = s.status === 'active' ? ' *** SPRINT ATUAL (ATIVA) ***' : s.status === 'planning' ? ' (planejamento)' : ' (concluída)';
      return `- ${s.name}${label}${s.start_date ? ` | Início: ${s.start_date.substring(0,10)}` : ''}${s.end_date ? ` | Fim: ${s.end_date.substring(0,10)}` : ''}`;
    }).join('\n')
  : 'Nenhuma sprint cadastrada.';

// Format tasks lists — include sprint name on each task
const formatTask = t => {
  let line = `- ${t.title}`;
  if (t.assigned_to_name) line += ` (${t.assigned_to_name})`;
  if (t.sprint_name) line += ` [Sprint: ${t.sprint_name}]`;
  return line;
};

const todoTasks = (projectData?.todoTasks || []).slice(0, 10);
const inProgressTasks = projectData?.inProgressTasks || [];
const blockedTasks = projectData?.blockedTasks || [];

const todoContext = todoTasks.length > 0
  ? todoTasks.map(formatTask).join('\n')
  : 'Nenhuma tarefa a fazer.';

const inProgressContext = inProgressTasks.length > 0
  ? inProgressTasks.map(formatTask).join('\n')
  : 'Nenhuma tarefa em progresso.';

const blockedContext = blockedTasks.length > 0
  ? blockedTasks.map(formatTask).join('\n')
  : 'Nenhuma tarefa bloqueada.';

// All tasks grouped by sprint (for sprint-specific queries)
const allTasks = projectData?.tasks || [];
const tasksBySprintContext = (() => {
  if (!allTasks.length) return 'Nenhuma tarefa cadastrada.';
  const groups = {};
  allTasks.forEach(t => {
    const key = t.sprint_name || 'Sem sprint';
    if (!groups[key]) groups[key] = [];
    groups[key].push(t);
  });
  return Object.entries(groups).map(([sprintName, tasks]) => {
    const isActive = sprints.find(s => s.name === sprintName && s.status === 'active');
    const header = isActive ? `### ${sprintName} (SPRINT ATUAL)` : `### ${sprintName}`;
    return header + '\n' + tasks.map(t => `  - [${t.status}] ${t.title}${t.assigned_to_name ? ` — ${t.assigned_to_name}` : ''}`).join('\n');
  }).join('\n\n');
})();

return {
  message: message.trim(),
  projectId,
  projectName: projectName || 'Projeto',
  userId,
  userEmail: userEmail || '',
  userName: userName || 'Usuário',
  teamMembers: formattedTeamMembers,
  teamMembersContext,
  projectStatsContext,
  workloadContext,
  sprintsContext,
  todoContext,
  inProgressContext,
  blockedContext,
  tasksBySprintContext,
  activeSprint: activeSprint ? activeSprint.name : null,
  hasProjectData: !!projectData,
  humandChannelId: humandChannelId || null,
  timestamp: new Date().toISOString()
};

