// Email sent successfully
const data = $('Parse Response').first().json;
const names = (data.recipientNames || data.recipients || []).join(', ');
const alsoHumand = data.also_sent_humand === true;

let channelMsg;
if (alsoHumand) {
  channelMsg = `✅ Mensagem enviada para ${names} via Humand e por e-mail.`;
} else {
  channelMsg = `✅ E-mail enviado com sucesso para ${names}.`;
}

return {
  success: true,
  type: 'email_sent',
  message: channelMsg + '\n\nO destinatário foi avisado que não é possível responder à Ada por esses canais — para dar continuidade ao assunto, ele deve acessar o Daher Plan.',
  timestamp: new Date().toISOString()
};

// Return clarification question
const data = $input.first().json;

return {
  success: true,
  type: 'clarification',
  message: data.clarificationQuestion || 'Poderia me dar mais detalhes sobre para quem você gostaria de enviar o e-mail?',
  timestamp: new Date().toISOString()
};

// Return answer response
const data = $input.first().json;
const msg = data.message || 'Desculpe, não consegui processar sua pergunta.';

// If the AI mentioned sending via Humand, append the no-reply clarification
const humandMentioned = /humand/i.test(msg) && /(enviada?|enviado?|mensagem)/i.test(msg);
const finalMsg = humandMentioned && !/não é possível responder/i.test(msg)
  ? msg + '\n\nO destinatário foi avisado que não pode responder à Ada pelo Humand — para continuar o assunto, ele deve acessar o Daher Plan.'
  : msg;

return {
  success: true,
  type: 'answer',
  message: finalMsg,
  timestamp: new Date().toISOString()
};

// Return error response
const data = $input.first().json;

return {
  success: false,
  type: 'error',
  message: data.errorMessage || 'Ocorreu um erro ao processar sua solicitação.',
  timestamp: new Date().toISOString()
};

try {
  // O AI envia o query como JSON string: {"ids":["CPF"],"text":"mensagem"}
  const q = (typeof query !== 'undefined' && query) ? String(query).trim() : '';
  if (!q) {
    return JSON.stringify({ success: false, error: 'Query vazia. O input deve ser JSON: {"ids":["CPF"],"text":"mensagem"}' });
  }

  let parsed;
  try {
    parsed = JSON.parse(q);
  } catch (_parseErr) {
    return JSON.stringify({ success: false, error: 'Query não é JSON válido. Formato esperado: {"ids":["CPF"],"text":"mensagem"}', received: q.substring(0, 200) });
  }

  const externalIds = Array.isArray(parsed.ids) ? parsed.ids : [parsed.ids || parsed.employee_external_ids || parsed.id].filter(Boolean);
  const text = parsed.text || parsed.message || '';

  if (!externalIds.length || !text) {
    return JSON.stringify({ success: false, error: 'JSON deve conter ids (array de CPFs) e text (mensagem)', received: parsed });
  }

  const BASE_URL = 'https://api-prod.humand.co/api/v1';
  const AUTH = 'Basic ODQwNDU3NjpqMVdzTDVwRnB5QlgteEhHTjNtMDNWc3djSDJMTFhYMg==';

  function ulid() {
    const chars = '0123456789ABCDEFGHJKMNPQRSTVWXYZ';
    let t = Date.now();
    let tEnc = '';
    for (let i = 0; i < 10; i++) { tEnc = chars[t % 32] + tEnc; t = Math.floor(t / 32); }
    let rEnc = '';
    for (let i = 0; i < 16; i++) rEnc += chars[Math.floor(Math.random() * 32)];
    return tEnc + rEnc;
  }

  const results = [];

  for (const externalId of externalIds) {
    // Passo 1: abrir (ou recuperar) o canal DM da Ada com o destinatário
    let openData;
    try {
      openData = await helpers.httpRequest({
        method: 'POST',
        url: BASE_URL + '/marty/conversations.open',
        headers: { 'Authorization': AUTH, 'Content-Type': 'application/json', 'Idempotency-Key': ulid() },
        body: { external_ids: [externalId] },
        json: true
      });
      if (!openData.ok) {
        results.push({ externalId, success: false, error: 'Falha ao abrir conversa', details: openData });
        continue;
      }
    } catch (reqErr) {
      results.push({ externalId, success: false, error: 'Erro em conversations.open', details: String(reqErr) });
      continue;
    }

    const channelId = openData && openData.channel && openData.channel.id;
    if (!channelId) {
      results.push({ externalId, success: false, error: 'Channel ID não retornado' });
      continue;
    }

    // Passo 2: enviar a mensagem
    try {
      const msgData = await helpers.httpRequest({
        method: 'POST',
        url: BASE_URL + '/marty/chat.postMessage',
        headers: { 'Authorization': AUTH, 'Content-Type': 'application/json', 'Idempotency-Key': ulid() },
        body: { channel: channelId, text: text, mrkdwn: false },
        json: true
      });
      if (msgData.ok) {
        results.push({ externalId, success: true, channel: channelId, ts: msgData.ts });
      } else {
        results.push({ externalId, success: false, error: 'Falha ao enviar mensagem', details: msgData });
      }
    } catch (reqErr) {
      results.push({ externalId, success: false, error: 'Erro em chat.postMessage', details: String(reqErr) });
    }
  }

  const allOk = results.every(r => r.success);
  const sent = results.filter(r => r.success).length;
  return JSON.stringify({ success: allOk, message: sent + ' de ' + externalIds.length + ' mensagem(ns) enviada(s) com sucesso no Humand', results });

} catch (err) {
  return JSON.stringify({ success: false, error: 'Erro inesperado no tool', details: String(err) });
}
